
/* ===== RFLIX VERSION CACHE BUST ===== */
(function(){
  var RFLIX_VER = '605a';
  try{
    var storedVer = localStorage.getItem('rflix_app_ver');
    if(storedVer !== RFLIX_VER){
      // New version - clear stale API caches but keep user config/tokens
      var keysToKeep = ['rf_cfg','rf_trakt','rflix_lang','rflix_theme','rflix_ft',
                        'rflix_fu','rflix_ep_layout','rflix_trakt_id','rflix_trakt_secret'];
      var keepMap = {};
      keysToKeep.forEach(function(k){ try{ keepMap[k]=localStorage.getItem(k); }catch(_e){} });
      // Clear all rf_ prefixed cache keys
      var toRemove = [];
      for(var i=0;i<localStorage.length;i++){
        var k=localStorage.key(i);
        if(k && (k.indexOf('rf_api_')===0 || k.indexOf('rf_img_')===0 || k.indexOf('rf_fanart')===0)){
          toRemove.push(k);
        }
      }
      toRemove.forEach(function(k){ try{ localStorage.removeItem(k); }catch(_e){} });
      // Clear sessionStorage API cache
      try{ sessionStorage.removeItem('rf_api_cache'); }catch(_e){}
      // Restore kept values
      Object.keys(keepMap).forEach(function(k){ try{ if(keepMap[k]!==null) localStorage.setItem(k,keepMap[k]); }catch(_e){} });
      localStorage.setItem('rflix_app_ver', RFLIX_VER);
    }
  }catch(_e){}
})();
/* ===== END RFLIX VERSION CACHE BUST ===== */

/* ===== INLINE QR CODE GENERATOR ===== */
/* Minimal QR encoder for alphanumeric URLs - no CDN needed */
window.RflixQR=(function(){
  function makeQR(text,size){
    try{
      // Use Google Charts QR API as data URI via fetch
      // Fallback: display just the URL text
      var el=document.createElement('div');
      el.style.cssText='width:'+size+'px;height:'+size+'px;display:flex;align-items:center;justify-content:center;background:#fff;border-radius:8px;padding:8px;box-sizing:border-box;';
      var img=document.createElement('img');
      // Use a public QR API
      var apiUrl='https://api.qrserver.com/v1/create-qr-code/?size='+size+'x'+size+'&data='+encodeURIComponent(text)+'&margin=2';
      img.src=apiUrl;
      img.style.cssText='width:100%;height:100%;';
      img.onerror=function(){
        // If API fails show text fallback
        el.innerHTML='<div style="font-size:10px;color:#000;text-align:center;word-break:break-all;padding:4px">'+text+'</div>';
      };
      el.appendChild(img);
      return el;
    }catch(_e){
      var fb=document.createElement('div');
      fb.style.cssText='width:'+size+'px;height:'+size+'px;background:#fff;border-radius:8px;display:flex;align-items:center;justify-content:center;padding:8px;box-sizing:border-box;';
      fb.innerHTML='<div style="font-size:9px;color:#000;text-align:center;word-break:break-all;">'+text+'</div>';
      return fb;
    }
  }
  return {make:makeQR};
})();
/* ===== END INLINE QR CODE GENERATOR ===== */



