// ===== NAV ICON PACKS (Classic, Heroicons Outline/Solid, Phosphor Bold, Tabler Filled - all MIT licensed) =====
var IconPacks = {
  apply: function(packId){
    try{
      var pack = null;
      for(var i=0;i<RFLIX_ICON_PACKS.length;i++){ if(RFLIX_ICON_PACKS[i].id===packId){ pack=RFLIX_ICON_PACKS[i]; break; } }
      if(!pack) pack = RFLIX_ICON_PACKS[0];
      var map = {search:'search', home:'home', tv:'tv', movies:'movies', discover:'discover', settings:'settings'};
      Object.keys(map).forEach(function(navKey){
        var btn = document.querySelector('.nav-item[data-nav="'+navKey+'"]');
        if(!btn) return;
        var svg = btn.querySelector('svg');
        if(!svg) return;
        var icon = pack.icons[map[navKey]];
        if(!icon) return;
        svg.setAttribute('viewBox', icon.vb || '0 0 24 24');
        if(pack.mode === 'stroke'){
          svg.setAttribute('fill', 'none');
          svg.setAttribute('stroke', 'currentColor');
          svg.setAttribute('stroke-width', '1.5');
        } else {
          svg.removeAttribute('stroke');
          svg.setAttribute('fill', 'currentColor');
        }
        var pathsHtml = icon.paths.map(function(p){
          var extra = '';
          if(p.fr) extra += ' fill-rule="'+p.fr+'"';
          if(p.cr) extra += ' clip-rule="'+p.cr+'"';
          if(pack.mode === 'stroke') extra += ' stroke-linecap="round" stroke-linejoin="round"';
          return '<path d="'+p.d+'"'+extra+'/>';
        }).join('');
        svg.innerHTML = pathsHtml;
      });
    }catch(_e){}
  },
  current: function(){
    try{ return (S.cfg && S.cfg.iconPack) || 'classic'; }catch(_e){ return 'classic'; }
  },
  set: function(packId){
    if(!S.cfg) S.cfg = {};
    S.cfg.iconPack = packId;
    try{ Stor.set('cfg', S.cfg); }catch(_e){}
    IconPacks.apply(packId);
  },
  label: function(packId){
    for(var i=0;i<RFLIX_ICON_PACKS.length;i++){ if(RFLIX_ICON_PACKS[i].id===packId) return RFLIX_ICON_PACKS[i].name; }
    return 'Classic';
  },
  _miniSvg: function(icon, mode){
    var attrs = mode === 'stroke'
      ? 'fill="none" stroke="white" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"'
      : 'fill="white"';
    var pathsHtml = icon.paths.map(function(p){
      var extra = '';
      if(p.fr) extra += ' fill-rule="'+p.fr+'"';
      if(p.cr) extra += ' clip-rule="'+p.cr+'"';
      return '<path d="'+p.d+'"'+extra+'/>';
    }).join('');
    return '<svg viewBox="'+(icon.vb||'0 0 24 24')+'" width="20" height="20" '+attrs+'>'+pathsHtml+'</svg>';
  },
  openPicker: function(){
    var cur = IconPacks.current();
    var ov = document.createElement('div');
    ov.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.92);display:flex;align-items:center;justify-content:center;';
    var box = document.createElement('div');
    box.style.cssText = 'background:#1a1a1a;border:1px solid #444;border-radius:16px;padding:20px;min-width:320px;max-width:92vw;max-height:86vh;overflow-y:auto;';
    var title = document.createElement('div');
    title.textContent = 'Icon Pack';
    title.style.cssText = 'color:#fff;font-size:18px;font-weight:700;margin-bottom:16px;text-align:center;';
    box.appendChild(title);
    RFLIX_ICON_PACKS.forEach(function(pack){
      var isCur = pack.id === cur;
      var btn = document.createElement('button');
      btn.style.cssText = 'display:flex;align-items:center;gap:12px;width:100%;padding:12px 14px;margin:6px 0;background:'+(isCur?'var(--glass)':'rgba(255,255,255,.07)')+';border:1px solid '+(isCur?'var(--accent)':'rgba(255,255,255,.15)')+';border-radius:10px;color:#fff;font-size:15px;font-weight:600;cursor:pointer;text-align:left;';
      var iconsRow = document.createElement('span');
      iconsRow.style.cssText = 'display:flex;gap:7px;flex-shrink:0;';
      ['home','tv','movies','discover','settings'].forEach(function(k){
        iconsRow.innerHTML += IconPacks._miniSvg(pack.icons[k], pack.mode);
      });
      var label = document.createElement('span');
      label.textContent = pack.name;
      label.style.cssText = 'flex:1;';
      btn.appendChild(iconsRow);
      btn.appendChild(label);
      btn.onclick = function(){
        IconPacks.set(pack.id);
        try{ Settings.upd(); }catch(_e){}
        try{ toast('Icon pack: '+pack.name); }catch(_e){}
        document.body.removeChild(ov);
      };
      box.appendChild(btn);
    });
    var cancel = document.createElement('button');
    cancel.textContent = 'Cancel';
    cancel.style.cssText = 'display:block;width:100%;padding:10px;margin-top:10px;background:transparent;border:1px solid rgba(255,255,255,.15);border-radius:10px;color:rgba(255,255,255,.7);font-size:15px;cursor:pointer;';
    cancel.onclick = function(){ document.body.removeChild(ov); };
    box.appendChild(cancel);
    ov.appendChild(box);
    document.body.appendChild(ov);
  }
};


// ===== CACHE BUST ON VERSION CHANGE =====
(function(){
  try{
    var BUILD_ID = '20260606_v15e';
    var stored = localStorage.getItem('rf_build_id');
    if(stored !== BUILD_ID){
      // Only clear caches if this is an UPGRADE (stored id exists but differs)
      // On fresh install (no stored id), skip the clear to avoid wiping nothing
      if(stored !== null){
        // Upgrade: clear stale caches but keep all user data and credentials
        var keep = {};
        var keepKeys = ['rf_tmdb_key','rf_cfg','rf_iptv_creds','rf_iptv_playlists',
          'rf_ltv_cfg','rf_trakt_token','rf_trakt_refresh','rf_favs','rf_trakt_cache',
          'vod_cw_v2'];
        keepKeys.forEach(function(k){
          try{ var v=localStorage.getItem(k); if(v!=null) keep[k]=v; }catch(_){}
        });
        // Also preserve any rf_vod_items_* and rf_iptv_vod_state_cache_* keys
        try{
          Object.keys(localStorage).forEach(function(k){
            if(k.indexOf('rf_vod_items_')===0 || k.indexOf('rf_iptv_vod_state_cache_')===0
               || k.indexOf('ltv_xtream_')===0 || k.indexOf('ltv_epg_')===0){
              try{ var v=localStorage.getItem(k); if(v!=null) keep[k]=v; }catch(_){}
            }
          });
        }catch(_){}
        localStorage.clear();
        Object.keys(keep).forEach(function(k){
          try{ localStorage.setItem(k, keep[k]); }catch(_){}
        });
      }
      localStorage.setItem('rf_build_id', BUILD_ID);
    }
  }catch(_e){}
})();

// ===== HTML ESCAPE (global) =====
function esc(t){
  try{
    return String(t||'')
      .replace(/&/g,'&amp;')
      .replace(/</g,'&lt;')
      .replace(/>/g,'&gt;')
      .replace(/"/g,'&quot;')
      .replace(/'/g,'&#39;');
  }catch(_e){return ''}
}


