// ===== NATIVE FETCH BRIDGE (ANDROID WEBVIEW CORS BYPASS) =====
(function installNativeFetchBridge(){
  try{
    if(!window.Android || typeof window.Android.nativeFetch!=='function') return;
    if(window.__nativeFetchInstalled) return;

    var originalFetch = window.fetch ? window.fetch.bind(window) : null;
    var pending = Object.create(null);

    function normalizeHeaders(h){
      try{
        if(!h) return {};
        if(typeof Headers!=='undefined' && h instanceof Headers){
          var out = {};
          h.forEach(function(v,k){ out[k]=v; });
          return out;
        }
        if(Array.isArray(h)){
          var out2 = {};
          h.forEach(function(pair){ if(pair && pair.length>=2) out2[String(pair[0])] = String(pair[1]); });
          return out2;
        }
        if(typeof h==='object') return h;
      }catch(_e){}
      return {};
    }

    function makeHeaders(headersObj){
      var map = {};
      try{
        Object.keys(headersObj||{}).forEach(function(k){ map[String(k).toLowerCase()] = String(headersObj[k]); });
      }catch(_e){}
      return {
        get:function(name){ return map[String(name||'').toLowerCase()] || null; },
        has:function(name){ return Object.prototype.hasOwnProperty.call(map, String(name||'').toLowerCase()); },
        forEach:function(cb){ Object.keys(map).forEach(function(k){ cb(map[k], k); }); }
      };
    }

    function parseMaybeJson(text){
      if(typeof text!=='string') return text;
      var t = text.trim();
      if(!t) return {};
      try{ return JSON.parse(t); }catch(_e){ return { _rawText:text }; }
    }

    window.__nativeFetchResolve = function(requestId, payload){
      try{
        var p = pending[requestId];
        if(!p) return;
        delete pending[requestId];

        var status = (payload && typeof payload.status==='number') ? payload.status : 0;
        var ok = !!(payload && payload.ok);
        var body = (payload && typeof payload.body==='string') ? payload.body : '';
        var headers = (payload && payload.headers && typeof payload.headers==='object') ? payload.headers : {};

        var response = {
          ok: ok,
          status: status,
          statusText: (payload && payload.statusText) ? String(payload.statusText) : '',
          headers: makeHeaders(headers),
          url: (payload && payload.url) ? String(payload.url) : p.url,
          text:function(){ return Promise.resolve(body); },
          json:function(){ return Promise.resolve(parseMaybeJson(body)); },
          clone:function(){ return this; }
        };

        p.resolve(response);
      }catch(e){
        try{ console.error('nativeFetch resolve failure', e); }catch(_e){}
      }
    };

    window.fetch = function(input, init){
      try{
        var url = '';
        if(typeof input === 'string') url = input;
        else if(input && input.url) url = String(input.url);

        function isTorBoxUrl(u){
          try{ return /(^https?:\/\/[^\/]*torbox\.app\/)/i.test(String(u||'')); }
          catch(_e){ return false; }
        }

        if(!/^https?:\/\//i.test(url)){
          if(originalFetch) return originalFetch(input, init);
          return Promise.reject(new Error('nativeFetch supports http(s) only'));
        }

        var cfg = init || {};
        var method = String(cfg.method || (input && input.method) || 'GET').toUpperCase();
        var headers = normalizeHeaders(cfg.headers || (input && input.headers) || {});
        var rawBody = (cfg.body!=null) ? cfg.body : ((input && input.body!=null) ? input.body : null);
        var body = '';

        if(rawBody!=null){
          try{
            if(typeof FormData!=='undefined' && rawBody instanceof FormData){
              var boundary = '----rflixnative'+Math.random().toString(16).slice(2)+Date.now();
              var lines = [];
              rawBody.forEach(function(v,k){
                try{
                  lines.push('--'+boundary);
                  lines.push('Content-Disposition: form-data; name="'+String(k).replace(/"/g,'')+'"');
                  lines.push('');
                  lines.push(v==null ? '' : String(v));
                }catch(_e0){}
              });
              lines.push('--'+boundary+'--');
              lines.push('');
              body = lines.join('\r\n');
              if(!headers['Content-Type'] && !headers['content-type']){
                headers['Content-Type'] = 'multipart/form-data; boundary='+boundary;
              }
            }else if(typeof URLSearchParams!=='undefined' && rawBody instanceof URLSearchParams){
              body = rawBody.toString();
              if(!headers['Content-Type'] && !headers['content-type']){
                headers['Content-Type'] = 'application/x-www-form-urlencoded;charset=UTF-8';
              }
            }else if(typeof rawBody === 'string'){
              body = rawBody;
            }else{
              body = String(rawBody);
            }
          }catch(_eBody){
            body = String(rawBody);
          }
        }
        var requestId = 'nf_'+Date.now()+'_'+Math.random().toString(36).slice(2);

        function doNative(){
          return new Promise(function(resolve, reject){
            pending[requestId] = { resolve:resolve, reject:reject, url:url };
            try{
              window.Android.nativeFetch(requestId, url, method, JSON.stringify(headers||{}), body);
            }catch(e){
              delete pending[requestId];
              reject(e);
            }
          });
        }

        // TorBox works best with stock browser fetch semantics (v16 behavior).
        // Keep native bridge as fallback only if browser fetch fails.
        if(isTorBoxUrl(url) && originalFetch){
          return originalFetch(input, init).catch(function(){ return doNative(); });
        }

        return doNative();
      }catch(e){
        return Promise.reject(e);
      }
    };

    window.__nativeFetchInstalled = true;
    try{ console.log('[RFlix] nativeFetch bridge installed'); }catch(_e){}
  }catch(_eOuter){}
})();

/**
 * Focus an element inside the Details modal without allowing the modal to
 * vertically scroll/offset. Android TV WebView can scroll a scroll-container
 * when focus changes; we immediately restore scrollTop.
 */
function focusNoScroll(el){
  if(!el) return;
  var dm = $('detail-modal');
  var st = dm ? (dm.scrollTop||0) : 0;
  try{
    if(el.focus){
      try{ el.focus({preventScroll:true}); }
      catch(_e){ el.focus(); }
    }
  }finally{
    if(dm) dm.scrollTop = st;
  }
}

/**
 * Ensure a focused element inside the Details modal is fully visible vertically.
 * Only adjusts scrollTop when the element is clipped.
 */
function ensureVisibleInDetail(el, pad){
  try{
    var dm = $('detail-modal');
    if(!dm || !el || !el.getBoundingClientRect) return;
    pad = (pad==null) ? 18 : (parseInt(pad,10)||0);

    var er = el.getBoundingClientRect();
    var dr = dm.getBoundingClientRect();

    if(er.bottom > (dr.bottom - pad)){
      dm.scrollTop += (er.bottom - (dr.bottom - pad));
      return;
    }
    if(er.top < (dr.top + pad)){
      dm.scrollTop -= ((dr.top + pad) - er.top);
      return;
    }
  }catch(_e){}
}

/**
 * Keep the focused element in Details around the visual center while navigating
 * (especially when moving between action buttons and cast rows).
 */
function centerFocusInDetail(el){
  try{
    var dm = $('detail-modal');
    if(!dm || !el) return;
    if(!dm.classList || !dm.classList.contains('open')) return;
    if(!dm.contains(el)) return;

    var er = el.getBoundingClientRect();
    var dr = dm.getBoundingClientRect();

    // Target focus center a bit above true center (feels more like Netflix/Weyd)
    var targetY = dr.top + Math.min(dr.height * 0.44, dr.height - 140);
    var elY = (er.top + er.bottom) / 2;
    var delta = elY - targetY;

    // Small movements shouldn't cause scroll jitter
    if(Math.abs(delta) < 28) return;

    dm.scrollTop += delta;
  }catch(_e){}
}

/** Center a focused card within its horizontal row without affecting Y scroll. */
function centerInRow(row, el){
  try{
    if(!row || !el) return;
    var left = el.offsetLeft - (row.clientWidth/2 - el.clientWidth/2);
    if(left < 0) left = 0;
    var max = row.scrollWidth - row.clientWidth;
    if(left > max) left = max;
    row.scrollLeft = left;

    // Fallback: Shield/Android TV WebView sometimes fails to visually scroll
    // even after setting scrollLeft. Force visibility based on bounding rects.
    try{
      var rr = row.getBoundingClientRect();
      var er = el.getBoundingClientRect();
      var pad = 24;
      if(er.right > rr.right - pad){
        row.scrollLeft += (er.right - (rr.right - pad));
      }else if(er.left < rr.left + pad){
        row.scrollLeft -= ((rr.left + pad) - er.left);
      }
    }catch(_e2){}
  }catch(_e){}
}
/** Center a focused tile inside a vertical scroll container (e.g., Discover grid). */
function centerInScroll(container, el, opts){
  try{
    if(!container || !el) return;
    opts = opts || {};
    var pad = (opts.pad!=null) ? opts.pad : 12; // keep some breathing room
    // Desired scrollTop so the element center aligns with viewport center.
    var target = (el.offsetTop||0) - (container.clientHeight/2 - el.clientHeight/2);
    // If card is very tall or container is small, fall back to "just keep fully visible".
    if(!isFinite(target)) return;
    var max = Math.max(0, (container.scrollHeight||0) - (container.clientHeight||0));
    if(target < 0) target = 0;
    if(target > max) target = max;

    // Avoid tiny oscillations.
    var cur = container.scrollTop||0;
    if(Math.abs(cur - target) < 2) return;

    // Use rAF so we don't fight focus/layout.
    try{
      if(container._rafCenter) cancelAnimationFrame(container._rafCenter);
    }catch(_eC){}
    container._rafCenter = requestAnimationFrame(function(){
      try{
        // If already comfortably visible, don't move.
        var cr = container.getBoundingClientRect();
        var er = el.getBoundingClientRect();
        var topOk = er.top >= cr.top + pad;
        var botOk = er.bottom <= cr.bottom - pad;
        if(topOk && botOk){
          // Still optionally keep "roughly centered" when navigating with DPAD.
          // Only recentre if it's drifting far from the middle.
          var mid = cr.top + cr.height/2;
          var emid = er.top + er.height/2;
          if(Math.abs(emid - mid) < (cr.height*0.20)) return;
        }
        container.scrollTop = target;
      }catch(_e){}
    });
  }catch(_e){}
}


/**
 * Force-center a focused card within its horizontal row.
 * Nvidia Shield / Android TV WebView can sometimes ignore the first scrollLeft
 * assignment (or paint it late). We re-apply after the current event loop and
 * across a couple of animation frames.
 */
function forceCenterInRow(row, el){
  try{
    if(!row || !el) return;

    // Some Android TV / Shield WebViews compute offsetLeft relative to a different offsetParent
    // in flex containers inside modals, which can prevent horizontal rows from visually scrolling.
    // Use a robust rect-based centering method instead.
    function rectCenter(){
      try{
        var rr=row.getBoundingClientRect();
        var er=el.getBoundingClientRect();
        var rowCenter = rr.left + (rr.width/2);
        var elCenter  = er.left + (er.width/2);
        var delta = elCenter - rowCenter;

        // Ignore tiny jitter
        if(Math.abs(delta) < 2) return;

        var max = row.scrollWidth - row.clientWidth;
        var next = (row.scrollLeft||0) + delta;
        if(next < 0) next = 0;
        if(next > max) next = max;

        // Apply + nudge to force a paint on some Shield builds
        row.scrollLeft = next;
        if((row.scrollLeft||0) === (next||0) && max>0){
          row.scrollLeft = Math.min(max, next+1);
          row.scrollLeft = next;
        }
      }catch(_e){}
    }

    rectCenter();

    // Re-apply after JS stack unwinds + across frames (helps Shield paint reliably)
    setTimeout(function(){
      try{ rectCenter(); }catch(_e1){}
      try{
        requestAnimationFrame(function(){
          try{ rectCenter(); }catch(_e2){}
          requestAnimationFrame(function(){
            try{ rectCenter(); }catch(_e3){}
          });
        });
      }catch(_e4){}
    }, 0);
  }catch(_e5){}
}



