var $$=function(s){return document.querySelectorAll(s)};

function pad2(n){ n=parseInt(n,10)||0; return (n<10?'0':'')+n; }
function fmtSE(sn,ep){ sn=parseInt(sn,10)||0; ep=parseInt(ep,10)||0; if(!sn||!ep) return ''; return 'S'+pad2(sn)+' • E'+pad2(ep); }

function fmtAir(ds){ try{ if(!ds) return ""; var d=new Date(ds); if(isNaN(d.getTime())) return ds; return d.toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"numeric"}); }catch(e){ return ds||""; } }
function upcomingSeason(it){
  try{
    var seasons = it && it.seasons;
    if(!seasons || !seasons.length) return null;
    var todayStr = new Date().toISOString().slice(0,10);
    var best = null;
    for(var i=0;i<seasons.length;i++){
      var s = seasons[i];
      if(!s || !s.air_date) continue;
      var ad = String(s.air_date);
      if(ad.length < 10) continue;
      if(ad >= todayStr){
        if(!best || ad < best.air_date){
          best = {air_date: ad, season_number: (s.season_number!=null ? s.season_number : s.number), name: (s.name||"")};
        }
      }
    }
    return best;
  }catch(e){ return null; }
}



function toast(m,t){
  try{
    var c=$('toast');
    if(!c){
      c=document.createElement('div');
      c.id='toast';
      c.style.cssText='position:fixed;bottom:32px;left:0;right:0;display:flex;flex-direction:column;align-items:center;gap:8px;z-index:2147483647;pointer-events:none';
      document.body.appendChild(c);
    }
    var e=document.createElement('div');
    e.className='toast-msg'+(t?' '+t:'');
    e.textContent=m;
    if(!e.style.cssText){
      e.style.cssText='background:rgba(20,15,40,.95);color:#fff;padding:12px 20px;border-radius:24px;font-size:14px;border:1px solid rgba(255,255,255,.15);box-shadow:0 8px 24px rgba(0,0,0,.5)';
    }
    c.appendChild(e);
    setTimeout(function(){try{e.remove()}catch(_){}},3500);
  }catch(_eT){}
}

function loadingLogoHtml(label){
  label = label || 'Loading';
  return '<div class="loading-logo"><img src="logo.png" alt="R\'Flix"><div class="loading-logo-text">'+label+'<span class="dots" aria-hidden="true"><span>.</span><span>.</span><span>.</span></span></div></div>';
}

// ===== STORAGE =====
var Stor={
  get:function(k,d){try{var v=localStorage.getItem('rf_'+k);return v?JSON.parse(v):d}catch(e){return d}},
  set:function(k,v){try{localStorage.setItem('rf_'+k,JSON.stringify(v))}catch(e){}}
};


var SOURCE_CACHE_TTL_MS = 2*60*60*1000;
var LAST_RESOLVED_TTL_MS = 12*60*60*1000;
function playbackKeyFor(item,sn,ep){
  // Exact per-content playback key. Never allow one show's/movie's cached URL to bleed into another.
  try{
    if(!item || !item.id) return null;
    var mt = String(item.media_type || item.type || 'movie').toLowerCase();
    var id = String(item.id);
    if(mt === 'tv' || mt === 'show' || mt === 'episode'){
      var ss = parseInt(sn,10) || 1;
      var ee = parseInt(ep,10) || 1;
      return 'tv:' + id + ':S' + ss + ':E' + ee;
    }
    return 'movie:' + id;
  }catch(_e){ return null; }
}
function playbackKeyMatchesCurrent(key){
  try{ return !!key && !!S.item && key === playbackKeyFor(S.item,S.season,S.ep); }catch(_e){ return false; }
}
function getCachedSourcesFor(item, imdb, sn, ep){
  try{
    var key = playbackKeyFor(item,sn,ep);
    if(!key) return null;
    var obj = Stor.get('src_cache:'+key, null);
    if(!obj || !obj.ts || !obj.sources || !obj.sources.length) return null;
    if(imdb && obj.imdb && String(obj.imdb)!==String(imdb)) return null;
    if((Date.now() - obj.ts) > SOURCE_CACHE_TTL_MS) return null;
    return obj;
  }catch(_e){ return null; }
}
function setCachedSourcesFor(item, imdb, sn, ep, sources){
  try{
    var key = playbackKeyFor(item,sn,ep);
    if(!key || !sources || !sources.length) return;
    Stor.set('src_cache:'+key, { ts: Date.now(), imdb: imdb||'', sources: sources });
  }catch(_e){}
}
function getLastResolvedPlayback(item,sn,ep){
  try{
    var key = playbackKeyFor(item,sn,ep);
    if(!key) return null;
    var obj = Stor.get('last_resolved:'+key, null);
    if(!obj || !obj.url || !obj.ts) return null;
    if((Date.now() - obj.ts) > LAST_RESOLVED_TTL_MS) return null;
    if(obj.key && obj.key !== key) return null;
    return obj;
  }catch(_e){ return null; }
}
function setLastResolvedPlayback(item,sn,ep,url,meta){
  try{
    var key = playbackKeyFor(item,sn,ep);
    if(!key || !url) return;
    Stor.set('last_resolved:'+key, {
      ts: Date.now(),
      key: key,
      mediaType: (item && (item.media_type||item.type)) || 'movie',
      itemId: item && item.id ? String(item.id) : '',
      season: ((item && (item.media_type==='tv'||item.type==='tv')) ? (parseInt(sn,10)||1) : 0),
      episode: ((item && (item.media_type==='tv'||item.type==='tv')) ? (parseInt(ep,10)||1) : 0),
      url: String(url),
      title: meta && meta.title ? meta.title : '',
      sourceTitle: meta && meta.sourceTitle ? meta.sourceTitle : '',
      hash: meta && meta.hash ? meta.hash : null,
      sourceUrl: meta && meta.sourceUrl ? meta.sourceUrl : null
    });
  }catch(_e){}
}

// ===== AUTO-FALLBACK (playback failures) =====
var Fallback = {
  active:false,
  order:[],
  curIdx:-1,
  attempts:0,
  maxAttempts:5,
  lock:false,

  start:function(order, curIdx){
    this.active=true;
    this.order=order||[];
    this.curIdx=curIdx;
    this.attempts=0;
    this.lock=false;
  },
  stop:function(){
    this.active=false;
    this.order=[];
    this.curIdx=-1;
    this.attempts=0;
    this.lock=false;
  },
  next:function(){
    if(!this.active) return null;
    var pos=this.order.indexOf(this.curIdx);
    for(var i=pos+1;i<this.order.length;i++){
      var n=this.order[i];
      if(typeof n==='number') return n;
    }
    return null;
  },
  fail:function(reason){
    if(!this.active) return false;
    if(this.lock) return false;
    this.lock=true;

    this.attempts++;
    if(this.attempts>this.maxAttempts){
      this.lock=false;
      this.stop();
      try{ toast('Too many failures — opening chooser…','error'); }catch(_e){}
      try{
        if(AIOPick && AIOPick.open){
          var aio = (S.sources||[]).filter(function(s){return s && s._aio;});
          if(aio.length){
            AIOPick.open(aio, function(sel){
              try{
                var idx = (S.sources||[]).indexOf(sel);
                if(idx>=0) Sources.play(idx, null, {fromFallback:true});
              }catch(_e){}
            });
          }
        }
      }catch(_e2){}
      return false;
    }

    var n=this.next();
    if(n==null){
      this.lock=false;
      this.stop();
      try{ toast('No more sources — opening AIO chooser…','error'); }catch(_e3){}
      try{
        if(AIOPick && AIOPick.open){
          var aio2 = (S.sources||[]).filter(function(s){return s && s._aio;});
          if(aio2.length){
            AIOPick.open(aio2, function(sel2){
              try{
                var idx2 = (S.sources||[]).indexOf(sel2);
                if(idx2>=0) Sources.play(idx2, null, {fromFallback:true});
              }catch(_e){}
            });
          }
        }
      }catch(_e4){}
      return false;
    }

    this.curIdx=n;
    this.lock=false;
    try{ toast((reason||'Playback issue')+' — trying next source…','error'); }catch(_e5){}
    setTimeout(function(){ try{ Sources.play(n, null, {fromFallback:true}); }catch(_e){} }, 120);
    return true;
  }
};

// ===== TMDB =====

// ===== KIDS MODE =====
// A conservative allow-list filter so the entire app can switch to children-only content
// without changing any layout.
var Kids=(function(){
  // TMDB genre IDs commonly associated with children's content:
  // 16 Animation, 10751 Family, 10762 Kids (TV)
  var ALLOW_GENRES = {16:1, 10751:1, 10762:1};
  var _railCache = {}; // kids rails cache for fast profile switching


  function enabled(){
    try{ return !!(S && S.cfg && S.cfg.kidsMode); }catch(_e){ return false; }
  }

  function hasAllowedGenre(it){
    try{
      var ids = [];
      if(it && Array.isArray(it.genre_ids)) ids = it.genre_ids;
      else if(it && Array.isArray(it.genres)) ids = it.genres.map(function(g){ return g && g.id; }).filter(Boolean);
      for(var i=0;i<ids.length;i++){
        if(ALLOW_GENRES[ids[i]]) return true;
      }
    }catch(_e){}
    return false;
  }

  function isKidSafe(it){
    try{
      if(!it) return false;
      // English-only in Kids mode (metadata-level).
      // TMDB provides ISO 639-1 in original_language.
      if(it.original_language && String(it.original_language).toLowerCase()!=='en') return false;
      // Never show people in Kids mode (search/multi returns persons).
      if(it.media_type==='person' || it.known_for_department==='Acting' && it.profile_path) return false;
      if(it.adult===true) return false;
      // English-only: hide non-English originals in Kids mode
      try{ if(it.original_language && String(it.original_language).toLowerCase()!=='en') return false; }catch(_eLang){}
      // If we have genres, require an allowed genre.
      if(Array.isArray(it.genre_ids) || Array.isArray(it.genres)){
        return hasAllowedGenre(it);
      }
      // If we don't know genres, keep it only if it looks like animation/family by title.
      var t = String(it.title||it.name||'').toLowerCase();
      if(/kids|kid|family|animation|cartoon|disney|pixar|dreamworks/.test(t)) return true;
      return false;
    }catch(_e){ return false; }
  }

  function filterList(list){
    try{
      if(!Array.isArray(list)) return list;
      return list.filter(isKidSafe);
    }catch(_e){ return list; }
  }

  function filterPayload(j){
    try{
      if(!enabled() || !j) return j;
      if(Array.isArray(j.results)) j.results = filterList(j.results);
      // Some endpoints (combined_credits) use cast/crew.
      if(Array.isArray(j.cast)) j.cast = filterList(j.cast);
      if(Array.isArray(j.crew)) j.crew = filterList(j.crew);
    }catch(_e){}
    return j;
  }

  // Build a Kids-safe TMDB rail with a target number of items by cascading years.
// This keeps rows full even when the current year has few kids titles.
function _kidsGenresParam(type){
  // 16 Animation, 10751 Family, 10762 Kids (TV only)
  // IMPORTANT: 10762 can break /discover/movie on some TMDB gateways, so only include it for TV.
  return (type==='tv') ? '16,10751,10762' : '16,10751';
}

function _yearParam(type, year, q){
  q = q || {};
  try{
    if(type==='tv'){
      q['first_air_date.gte'] = year+'-01-01';
      q['first_air_date.lte'] = year+'-12-31';
      try{ delete q.first_air_date_year; }catch(_e){}
    }else{
      q['primary_release_date.gte'] = year+'-01-01';
      q['primary_release_date.lte'] = year+'-12-31';
      try{ delete q.primary_release_year; }catch(_e2){}
    }
  }catch(_e3){}
  return q;
}


function fetchRail(type, kind, target, opts){
  type = (type==='tv') ? 'tv' : 'movie';
  target = target || 100;
  opts = opts || {};

  // Cache per (kidsOn,type,kind,target). Kids mode can be toggled at runtime.
    var cacheKey = (enabled()?'K':'N') + ':' + type + ':' + kind + ':' + target;
  var nowTs = Date.now();
  try{
    var c = _railCache[cacheKey];
    // Serve cached rows quickly when switching profiles/sections.
    if(c && c.items && c.items.length && (nowTs - (c.ts||0) < 30*60*1000)){
      return Promise.resolve(c.items.slice(0, target));
    }
  }catch(_eC){}

  // "Popular" -> popularity.desc
  // "Trending" -> vote_count.desc (keeps it feeling current without needing /trending)
  var sortBy = (kind==='trending') ? 'vote_count.desc' : 'popularity.desc';

  var startYear = (new Date()).getFullYear();
  var minYear = 1950;

  var out = [];
  var seen = {};

  function pushAll(list){
    (list||[]).forEach(function(it){
      if(!it || !it.id) return;
      var k = type+':'+it.id;
      if(seen[k]) return;
      seen[k]=1;
      it.media_type = it.media_type || type;
      if(isKidSafe(it)) out.push(it);
    });
  }

  function mkQ(year, page){
    var q = { include_adult:false, with_genres:_kidsGenresParam(type), with_original_language:'en', sort_by:sortBy, page:page||1 };
    q = _yearParam(type, year, q);
    return q;
  }

  // Fetch strategy: breadth-first across (year,page) with small concurrent batches.
  // This gets *some* content on screen quickly and still fills to the requested target.
  function fetchBatch(tasks){
    return Promise.all(tasks.map(function(t){
      return TMDB.discover(type, mkQ(t.year, t.page)).then(function(j){
        try{ pushAll((j&&j.results)||[]); }catch(_e){}
        return j && j.results && j.results.length;
      }).catch(function(){ return false; });
    }));
  }

  // Build a list of years to try. Prefer recent years but allow fallback until filled.
  var years = [];
  for(var y=startYear; y>=minYear; y--) years.push(y);

  // We'll try a few years at a time, and within each year a few pages at a time.
  var yearIdx = 0;
  var perYearMaxPages = 5;      // hard cap for safety
  var warmPages = 2;            // pages to try first per year
  var warmYears = 4;            // years to try first (current + 3)
  var conc = 3;                 // concurrent requests per batch

  function scheduleWarm(){
    var tasks = [];
    var endIdx = Math.min(yearIdx + warmYears, years.length);
    for(var i=yearIdx; i<endIdx; i++){
      var yr = years[i];
      for(var p=1; p<=warmPages; p++){
        tasks.push({year:yr, page:p});
      }
    }
    yearIdx = endIdx;
    return tasks;
  }

  function scheduleMore(){
    // After warmup, expand by adding one more page for the most recent N years we already touched,
    // then add another slice of older years.
    var tasks = [];
    // Add extra pages for recent years first
    var recentYears = years.slice(0, Math.min(warmYears, years.length));
    for(var i=0;i<recentYears.length;i++){
      var yr = recentYears[i];
      for(var p=warmPages+1; p<=perYearMaxPages; p++){
        tasks.push({year:yr, page:p});
      }
    }
    // Then older years, page 1..2
    var endIdx = Math.min(yearIdx + warmYears, years.length);
    for(var j=yearIdx; j<endIdx; j++){
      var y2 = years[j];
      for(var p2=1; p2<=warmPages; p2++){
        tasks.push({year:y2, page:p2});
      }
    }
    yearIdx = endIdx;
    return tasks;
  }

  function runTasks(allTasks){
    var idx=0;
    function next(){
      if(out.length>=target) return Promise.resolve(out.slice(0,target));
      if(idx>=allTasks.length){
        // If still short, keep walking years with 1..2 pages each.
        if(yearIdx>=years.length) return Promise.resolve(out.slice(0,target));
        var extra = [];
        var endIdx = Math.min(yearIdx + warmYears, years.length);
        for(var k=yearIdx; k<endIdx; k++){
          for(var p=1; p<=warmPages; p++) extra.push({year:years[k], page:p});
        }
        yearIdx=endIdx;
        allTasks = extra;
        idx=0;
        if(!allTasks.length) return Promise.resolve(out.slice(0,target));
      }
      var batch = allTasks.slice(idx, idx+conc);
      idx += conc;
      return fetchBatch(batch).then(function(){ return next(); });
    }
    return next();
  }

  // Kick off warm tasks first (fast initial fill).
  var warm = scheduleWarm();
  return runTasks(warm).then(function(items){
    // If still not enough, continue with a heavier pass, but don't block UI for too long:
    // resolve with what we have after a short ceiling, and keep filling cache in background.
    if(items.length>=target){
      try{ _railCache[cacheKey] = {ts:Date.now(), items:items}; }catch(_eS){}
      return items;
    }

    // Background fill promise
    var bg = runTasks(scheduleMore()).then(function(more){
      var final = more.slice(0,target);
      try{ _railCache[cacheKey] = {ts:Date.now(), items:final}; }catch(_eS2){}
      return final;
    }).catch(function(){
      try{ _railCache[cacheKey] = {ts:Date.now(), items:items}; }catch(_eS3){}
      return items;
    });

    // Hard ceiling for initial render: return quickly with partial, then rely on cache
    // (rows will be fully populated the next time section is opened or after a refresh).
    if(opts && opts.fast){
      return Promise.race([bg, new Promise(function(res){ setTimeout(function(){ res(items); }, 1200); })]);
    }

    return bg;
  });
}

  return {enabled:enabled, filterList:filterList, filterPayload:filterPayload, isKidSafe:isKidSafe, fetchRail:fetchRail};
})();

