var Webstreamr={
  endpoints:[
    'https://94c8cb9f702d-webstreamr.baby-beamup.club',
    'https://webstreamr.strem.fun',
    'https://webstreamr.hayd.uk'
  ],
  _json:function(url){
    var ms=10000;
    if(typeof AbortController!=='undefined'){
      var c=new AbortController();
      var t=setTimeout(function(){try{c.abort();}catch(_e){}}, ms);
      return fetch(url,{headers:{'Accept':'application/json'},signal:c.signal}).then(function(r){
        clearTimeout(t);
        if(!r.ok) throw new Error('HTTP '+r.status);
        return r.json();
      }).catch(function(e){ clearTimeout(t); throw e; });
    }
    return Promise.race([
      fetch(url,{headers:{'Accept':'application/json'}}).then(function(r){
        if(!r.ok) throw new Error('HTTP '+r.status);
        return r.json();
      }),
      new Promise(function(_,rej){ setTimeout(function(){ rej(new Error('timeout')); }, ms); })
    ]);
  },
  _retry:function(url,n){
    var self=this;
    n=(typeof n==='number')?n:2;
    return self._json(url).catch(function(e){
      if(n<=0) throw e;
      return new Promise(function(res){setTimeout(res, 350);}).then(function(){return self._retry(url,n-1);});
    });
  },
  get:function(t,imdb,sn,ep){
    if(!imdb) return Promise.resolve([]);
    var type=(t==='movie')?'movie':'series';
    var id=imdb;
    if(type==='series'){
      sn=parseInt(sn,10)||1; ep=parseInt(ep,10)||1;
      id=imdb+':'+sn+':'+ep;
    }
    var urls=this.endpoints.map(function(b){
      return b.replace(/\/+$/,'')+'/stream/'+type+'/'+id+'.json';
    });
    var self=this;
    function tryOne(i){
      if(i>=urls.length) return Promise.resolve([]);
      return self._retry(urls[i],2).then(function(d){
        return (d && d.streams) ? d.streams : [];
      }).catch(function(){ return tryOne(i+1); });
    }
    return tryOne(0);
  },
  parse:function(st){
    st=st||[];
    return st.map(function(s){
      var t=(s&&(s.name||s.title))?String(s.name||s.title):'Webstreamr';
      var q='720p';
      if(/2160|4k|uhd/i.test(t))q='4K';else if(/1080/i.test(t))q='1080p';else if(/720/i.test(t))q='720p';else if(/480|sd/i.test(t))q='480p';
      var m=t.match(/(\d+\.?\d*)\s*(GB|MB)/i),sz=m?m[1]+' '+m[2].toUpperCase():'';
      var h=s&&(s.infoHash||s.infohash||s.hash)?String(s.infoHash||s.infohash||s.hash):'';
      var u=s&&s.url?String(s.url):'';
      if(!h && u && u.indexOf('magnet:')===0){
        var mh=u.match(/btih:([a-fA-F0-9]{40})/);
        if(mh) h=mh[1];
      }
      if(u && /^https?:/i.test(u)) h='';
      return {title:t.split('\n')[0].substring(0,60),q:q,sz:sz,hash:null,url:(u||null),source:'Webstreamr',_ws:true,_prov:'ws'};
    }).filter(function(x){ return x && x.url; });
  }
};


