                            // Prefer TorBox resolve for hashes/magnets
                            if(chosen.hash && TorBox && TorBox.resolveSource){
                              toast('Resolving TorBox...');
                              TorBox.resolveSource(chosen).then(function(u2){ if(u2) launch(u2); else if(chosen.url) launch(chosen.url); else resolve(false); }).catch(function(){ if(chosen.url) launch(chosen.url); else resolve(false); });
                              return;
                            }
                            if(chosen.url){ launch(chosen.url); return; }
