  setTorBoxToken:function(){
    var self=this;
    if(S.cfg.torboxToken && String(S.cfg.torboxToken).trim()){
      if(confirm('TorBox is linked. Unlink?')){
        S.cfg.torboxToken=''; Stor.set('cfg',S.cfg);
        toast('TorBox unlinked'); self.upd();
      }
      return;
    }
    toast('Requesting TorBox code...');
    fetch('https://api.torbox.app/v1/api/integration/devicecode', {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({client_id:'rflix_app'})
    }).then(function(r){return r.json();}).then(function(j){
      if(!j||!j.success||!j.data||!j.data.user_code||!j.data.device_code){
        toast('TorBox code request failed','error'); return;
      }
      var userCode=j.data.user_code;
      var deviceCode=j.data.device_code;
      var expires=parseInt(j.data.expires_in||600,10);
      var url='https://torbox.app/oauth/device';
      S.authSvc='torbox';
      $('auth-title').textContent='Link TorBox';
      $('auth-url').textContent='torbox.app/oauth/device';
      $('auth-url').href=url;
      $('auth-code').textContent=userCode;
      $('auth-status').textContent='Go to the link above and enter this code';
      Modal.open('auth'); $('auth-cancel').focus();
      var start=Date.now(); var linked=false;
      (function poll(){
        if(linked) return;
        var left=expires-Math.floor((Date.now()-start)/1000);
        if(left<=0){ toast('TorBox code expired','error'); return; }
        setTimeout(function(){
          if(linked) return;
          fetch('https://api.torbox.app/v1/api/integration/devicecode/check', {
            method:'POST',
            headers:{'Content-Type':'application/json'},
            body:JSON.stringify({client_id:'rflix_app', device_code:deviceCode})
          }).then(function(r){return r.json();}).then(function(pc){
            if(pc && pc.success && pc.data && pc.data.token){
              linked=true;
              S.cfg.torboxToken=String(pc.data.token).trim();
              Stor.set('cfg',S.cfg);
              toast('TorBox linked!','success');
              Modal.close('auth'); self.upd(); return;
            }
            poll();
          }).catch(function(){ poll(); });
        }, 5000);
      })();
    }).catch(function(_e){ toast('TorBox code request failed','error'); });
  },
  
  setPremiumizeKey:function(){
    var self=this;
    if(S.cfg.premiumizeKey && String(S.cfg.premiumizeKey).trim()){
      if(confirm('Premiumize is linked. Unlink?')){
        S.cfg.premiumizeKey=''; Stor.set('cfg',S.cfg);
        toast('Premiumize unlinked'); self.upd();
      }
      return;
    }
    toast('Requesting Premiumize code...');
    // Premiumize device code flow
    var PM_CLIENT='855400527';
    fetch('https://www.premiumize.me/token', {
      method:'POST',
      headers:{'Content-Type':'application/x-www-form-urlencoded'},
      body:'client_id='+PM_CLIENT+'&response_type=device_code'
    }).then(function(r){return r.json();}).then(function(j){
      if(!j||!j.user_code||!j.device_code){
        // Fallback to API key input if device flow fails
        var cur='';try{cur=S.cfg.premiumizeKey||'';}catch(e){}
        InputModal.open('Premiumize API Key','Enter your Premiumize API key from premiumize.me/account','API Key',cur,function(v){
          S.cfg.premiumizeKey=v||''; Stor.set('cfg',S.cfg);
          toast(v?'Premiumize key saved':'Premiumize key cleared'); self.upd();
        });
        return;
      }
      var userCode=j.user_code;
      var deviceCode=j.device_code;
      var expires=parseInt(j.expires_in||600,10);
      var interval=parseInt(j.interval||5,10)*1000;
      var verifyUrl=j.verification_uri||'https://www.premiumize.me/device';
      S.authSvc='premiumize';
      $('auth-title').textContent='Link Premiumize';
      $('auth-url').textContent='premiumize.me/device';
      $('auth-url').href=verifyUrl;
      $('auth-code').textContent=userCode;
      $('auth-status').textContent='Go to the link above and enter this code';
      Modal.open('auth'); $('auth-cancel').focus();
      var start=Date.now(); var linked=false;
      (function poll(){
        if(linked) return;
        var left=expires-Math.floor((Date.now()-start)/1000);
        if(left<=0){ toast('Premiumize code expired','error'); return; }
        setTimeout(function(){
          if(linked) return;
          fetch('https://www.premiumize.me/token', {
            method:'POST',
            headers:{'Content-Type':'application/x-www-form-urlencoded'},
            body:'client_id='+PM_CLIENT+'&grant_type=device_code&code='+encodeURIComponent(deviceCode)
          }).then(function(r){return r.json();}).then(function(pc){
            if(pc && pc.access_token){
              linked=true;
              S.cfg.premiumizeKey=String(pc.access_token).trim();
              Stor.set('cfg',S.cfg);
              toast('Premiumize linked!','success');
              Modal.close('auth'); self.upd(); return;
            }
            if(pc && (pc.error==='authorization_pending'||pc.error==='slow_down')){
              poll(); return;
            }
            // access_denied or expired — abort
            if(pc && pc.error && pc.error!=='authorization_pending'){
              toast('Premiumize: '+pc.error,'error'); return;
            }
            poll();
          }).catch(function(){ poll(); });
        }, interval);
      })();
    }).catch(function(_e){
      // Network error - fallback to API key
      var cur='';try{cur=S.cfg.premiumizeKey||'';}catch(e){}
      InputModal.open('Premiumize API Key','Enter your Premiumize API key from premiumize.me/account','API Key',cur,function(v){
        S.cfg.premiumizeKey=v||''; Stor.set('cfg',S.cfg);
        toast(v?'Premiumize key saved':'Premiumize key cleared'); self.upd();
      });
    });
  },
  // DebridLink - PIN/device code
  linkDebridLink:function(){
    var self=this;
    if(S.cfg.debridlinkToken){
      if(confirm('DebridLink is linked. Unlink?')){S.cfg.debridlinkToken='';Stor.set('cfg',S.cfg);toast('DebridLink unlinked');self.upd();}
      return;
    }
    toast('Requesting DebridLink PIN...');
    fetch('https://debrid-link.com/api/v2/pin/get?client_id=rflix_app')
      .then(function(r){return r.json();})
      .then(function(j){
        if(!j||!j.success||!j.value||!j.value.code){toast('DebridLink PIN failed','error');return;}
        var code=j.value.code, check=j.value.checkCode;
        S.authSvc='debridlink';
        $('auth-title').textContent='Link DebridLink';
        $('auth-url').textContent='debrid-link.com/pin';
        $('auth-url').href='https://debrid-link.com/pin/'+code;
        $('auth-code').textContent=code;
        $('auth-status').textContent='Open the link and enter the code, then wait here';
        Modal.open('auth');
      var _ac=$('auth-cancel');
      if(_ac){
        _ac.onclick=function(){clearInterval(S.authPoll);S.authPoll=null;Modal.close('auth');};
        setTimeout(function(){try{_ac.focus();}catch(_e){}},80);
      }
        S.authPoll=setInterval(function(){
          fetch('https://debrid-link.com/api/v2/pin/check?client_id=rflix_app&code='+code+'&check='+check)
            .then(function(r){return r.json();})
            .then(function(d){
              if(d&&d.success&&d.value&&d.value.access_token){
                clearInterval(S.authPoll);
                S.cfg.debridlinkToken=d.value.access_token;
                Stor.set('cfg',S.cfg);Modal.close('auth');
                toast('DebridLink linked!','success');self.upd();
              }
            }).catch(function(){});
        },5000);
      }).catch(function(){toast('DebridLink connection failed','error');});
  },

