// Capture-phase DPAD handler for Settings (prevents Shield WebView focus lock-ups)
// v43-fix: full two-pane awareness — sidebar nav-tabs + content setting-items
(function(){
  // ── helpers ─────────────────────────────────────────────────────────────
  function getNavTabs(){
    return Array.prototype.slice.call(
      document.querySelectorAll('#settings-modal .settings-nav .nav-tab')
    );
  }
  function getContentItems(){
    // Active panel only — setting-item, settings-row, setting-row, iptv-cred-row
    var panel = document.querySelector('#settings-modal .content-panel.active');
    if(!panel) return [];
    return Array.prototype.slice.call(
      panel.querySelectorAll('.setting-item, .settings-row, .setting-row, .iptv-cred-row, [tabindex="0"]')
    ).filter(function(el){ return el.offsetParent !== null; }); // visible only
  }
  function isInSidebar(el){
    if(!el) return false;
    var nav = document.querySelector('#settings-modal .settings-nav');
    return nav ? nav.contains(el) : false;
  }
  function isInContent(el){
    if(!el) return false;
    var panel = document.querySelector('#settings-modal .content-panel.active');
    return panel ? panel.contains(el) : false;
  }
  function activateNavTab(tab){
    if(!tab) return;
    var target = tab.getAttribute('data-target');
    document.querySelectorAll('.nav-tab').forEach(function(t){ t.classList.remove('active'); });
    document.querySelectorAll('.content-panel').forEach(function(p){ p.classList.remove('active'); });
    tab.classList.add('active');
    var panel = target ? document.getElementById(target) : null;
    if(panel) panel.classList.add('active');
  }
  function focusFirst(items){
    if(items && items.length){ items[0].focus(); try{ items[0].scrollIntoView({block:'center'}); }catch(_e){} }
  }
  function focusItem(items, idx){
    if(!items || !items.length) return;
    var t = items[Math.max(0, Math.min(items.length-1, idx))];
    if(t && t.focus){ t.focus(); try{ t.scrollIntoView({block:'center'}); }catch(_e){} }
  }

  function onCap(e){
    try{
      if(Modal.current()!=='settings') return;
      if(document.body.classList.contains('select-open')) return;
      try{ var icm=document.getElementById('iptv-cred-modal'); if(icm&&icm.classList.contains('open')) return; }catch(_e){}
      var k=(e&&e.key)||'';
      var code=e?e.keyCode:0;
      var isEnter = (k==='Enter'      || code===23 || code===66);
      var isUp    = (k==='ArrowUp'    || code===19);
      var isDown  = (k==='ArrowDown'  || code===20);
      var isLeft  = (k==='ArrowLeft'  || code===21);
      var isRight = (k==='ArrowRight' || code===22);
      if(!(isUp||isDown||isLeft||isRight||isEnter)) return;

      var ae = document.activeElement;

      // ── Focus is inside a cred-btn strip ──────────────────────────────
      var inCredBtn = ae && ae.classList && ae.classList.contains('iptv-cred-btn');
      if(inCredBtn){
        e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
        var credRow = ae.closest('.iptv-cred-row');
        var btns = credRow ? Array.prototype.slice.call(credRow.querySelectorAll('.iptv-cred-btn')) : [];
        var bi = btns.indexOf(ae);
        if(isRight){ if(bi < btns.length-1) btns[bi+1].focus(); return; }
        if(isLeft){ if(bi > 0) btns[bi-1].focus(); else if(credRow) credRow.focus(); return; }
        if(isEnter){ ae.click(); return; }
        if(isUp||isDown){
          // Move to adjacent content item from cred row
          var items = getContentItems();
          var ci = credRow ? items.indexOf(credRow) : -1;
          if(ci<0) ci=0;
          focusItem(items, isDown ? ci+1 : ci-1);
        }
        return;
      }

      // ── Focus is on a cred-row itself ──────────────────────────────────
      var inCredRow = ae && ae.classList && ae.classList.contains('iptv-cred-row');
      if(inCredRow){
        e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
        if(isRight){ var fb=ae.querySelector('.iptv-cred-btn'); if(fb) fb.focus(); return; }
        if(isLeft) return; // nothing to the left inside cred row
        if(isEnter){ ae.click(); return; }
        if(isUp||isDown){
          var items2 = getContentItems();
          var ci2 = items2.indexOf(ae);
          if(ci2<0) ci2=0;
          focusItem(items2, isDown ? ci2+1 : ci2-1);
        }
        return;
      }

      // ── Focus is in the sidebar ────────────────────────────────────────
      if(isInSidebar(ae)){
        e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
        var tabs = getNavTabs();
        var ti = tabs.indexOf(ae);
        if(ti<0){
          var parentTab = ae.closest ? ae.closest('.nav-tab') : null;
          ti = parentTab ? tabs.indexOf(parentTab) : 0;
        }
        if(ti<0) ti=0;
        if(isUp){ focusItem(tabs, ti-1); return; }
        if(isDown){ focusItem(tabs, ti+1); return; }
        if(isRight){
          // Move focus into the active content panel's first item
          var contentItems = getContentItems();
          focusFirst(contentItems);
          return;
        }
        if(isLeft) return; // already at leftmost pane
        if(isEnter){
          // Activate the tab (switch panel) and move focus into content
          activateNavTab(ae.classList.contains('nav-tab') ? ae : (ae.closest ? ae.closest('.nav-tab') : null));
          var ci3 = getContentItems();
          setTimeout(function(){ focusFirst(ci3.length ? ci3 : getContentItems()); }, 30);
          return;
        }
        return;
      }

      // ── Focus is in the content panel ─────────────────────────────────
      if(isInContent(ae)){
        e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
        var contentItems2 = getContentItems();
        var ci4 = contentItems2.indexOf(ae);
        if(ci4<0){
          var parentItem = ae.closest ? ae.closest('.setting-item, .settings-row, .setting-row, .iptv-cred-row') : null;
          ci4 = parentItem ? contentItems2.indexOf(parentItem) : 0;
        }
        if(ci4<0) ci4=0;
        if(isUp){ focusItem(contentItems2, ci4-1); return; }
        if(isDown){ focusItem(contentItems2, ci4+1); return; }
        if(isLeft){
          // Move focus back to the active sidebar tab
          var activeSideTab = document.querySelector('#settings-modal .settings-nav .nav-tab.active');
          if(activeSideTab){ activeSideTab.focus(); try{ activeSideTab.scrollIntoView({block:'center'}); }catch(_e){} }
          return;
        }
        if(isRight) return; // nothing to the right of content
        if(isEnter){
          var target2 = (ae.classList.contains('setting-item') || ae.classList.contains('settings-row') || ae.classList.contains('setting-row') || ae.classList.contains('iptv-cred-row'))
                        ? ae
                        : (ae.closest ? ae.closest('.setting-item, .settings-row, .setting-row') : null);
          if(target2){ try{ target2.click(); }catch(_eClk){} try{ S._settingsLastFocusId = target2.id||null; }catch(_eId){} }
          return;
        }
        return;
      }

      // ── Nothing focused yet — seed focus into sidebar ──────────────────
      if(isUp||isDown||isRight){
        e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
        var firstTab = document.querySelector('#settings-modal .settings-nav .nav-tab.active') ||
                       document.querySelector('#settings-modal .settings-nav .nav-tab');
        if(firstTab) firstTab.focus();
      }
    }catch(_e){}
  }
  document.addEventListener('keydown', onCap, true);
})();

