// -----------------------------
// DPAD Deep Dive Safety Layer
// -----------------------------
// Defensive layer to keep DPAD navigation alive across screens/modals and prevent embedded
// playback from trapping focus. Also ensures the Play control is DPAD-reachable.
(function(){
  try{
    var lastGoodFocus = null;
    function isDpadKey(ev){
      var c = ev.keyCode;
      return c===19||c===20||c===21||c===22||c===23||c===66||c===13;
    }
    document.addEventListener('focusin', function(){
      try{
        var a=document.activeElement;
        if(!a) return;
        if(a===document.body||a===document.documentElement) return;
        lastGoodFocus=a;
      }catch(e){}
    }, true);

    function firstFocusable(scope){
      try{
        var root = scope || document;
        return root.querySelector('[tabindex="0"], button, a[href], input, select, textarea, [role="button"]');
      }catch(e){ return null; }
    }

    function restoreFocus(){
      try{
        var a=document.activeElement;
        if(a && a!==document.body && a!==document.documentElement) return true;
        if(lastGoodFocus && document.contains(lastGoodFocus)){
          lastGoodFocus.focus();
          return true;
        }
        var modal=document.querySelector('.modal.show, .modal.open, #modal.show, #modal.open, [aria-modal="true"]');
        var f=firstFocusable(modal||document);
        if(f){ f.focus(); return true; }
      }catch(e){}
      return false;
    }

    document.addEventListener('keydown', function(ev){
      try{ if(isDpadKey(ev)) restoreFocus(); }catch(e){}
    }, true);

    function findPlayControl(){
      try{
        return document.querySelector('#play, .play, button.play, [data-action="play"], button[aria-label*="Play" i], [role="button"][aria-label*="Play" i]');
      }catch(e){ return null; }
    }

    function ensurePlaybackFocus(){
      try{
        // Best-effort detection of embedded playback state
        var player = document.querySelector('#embed, .embed, #player, .player, iframe, video');
        if(!player) return;
        var ifr=document.querySelector('iframe');
        if(ifr){
          ifr.setAttribute('tabindex','-1');
          ifr.setAttribute('aria-hidden','true');
        }
        var p=findPlayControl();
        if(p){ p.tabIndex=0; p.focus({preventScroll:true}); }
      }catch(e){}
    }

    document.addEventListener('click', function(){ setTimeout(ensurePlaybackFocus, 0); }, true);
    document.addEventListener('keydown', function(ev){
      try{
        if(!isDpadKey(ev)) return;
        if(document.querySelector('#embed, .embed, #player, .player')){
          var p=findPlayControl();
          if(p && document.activeElement!==p){ p.tabIndex=0; p.focus({preventScroll:true}); }
        }
      }catch(e){}
    }, true);
  }catch(_e){}
})();

// Shield fallback: some external players return without firing focus/visibility events.
// Poll visibility+focus and trigger auto-next on a "resumed" transition.


// Deterministic fallback: if we are back in the app and the external session has run long enough
// to meet the 92% threshold, trigger auto-next even if no resume events fired.
setInterval(function(){
  try{
    if(!(S._extPending || S._extAutoNextArmed)) return;
    if(!S.item || S.item.media_type!=='tv') return;
    var rt = (S._extRuntimeSec||45*60);
    var away = S._extStartTs ? (Date.now()-S._extStartTs)/1000 : 0;
    if(away < (rt*0.92)) return;
    // Only run when we are actually in this WebView.
    if(document.visibilityState && document.visibilityState!=='visible') return;
    // Some WebViews lie about focus; best effort.
    _handleExtReturn();
  }catch(_e){}
}, 1000);

S._wasVisible = (document.visibilityState==='visible' && (document.hasFocus?document.hasFocus():true));
setInterval(function(){
  try{
    var vis = (document.visibilityState==='visible');
    var foc = (document.hasFocus?document.hasFocus():true);
    var nowVis = (vis && foc);
    if(!S._wasVisible && nowVis){
      _handleExtReturn();
    }
    S._wasVisible = nowVis;
  }catch(_e){}
}, 1000);


/* ===== RFLIX: Focused Row Stays Bottom-Anchored (FINAL) ===== */
(() => {
  const ROW_SELECTORS = [
    "#rows-wrap .row-section",
    "#rows-wrap .row",
    ".row-section",
    ".content-row",
    ".rail",
    ".lane"
  ].join(",");

  const SCROLLER = () => {
    return document.getElementById("rows-wrap") ||
           document.getElementById("main") ||
           document.scrollingElement ||
           document.documentElement;
  };

  function instantScrollBy(deltaY){
    const el = SCROLLER();
    if (el === document.documentElement || el === document.body || el === document.scrollingElement){
      window.scrollBy(0, deltaY);
    } else {
      el.scrollTop += deltaY;
    }
  }

  function pinRowToBottom(rowEl){
    if (!rowEl) return;

    const rect = rowEl.getBoundingClientRect();
    const viewportBottom = window.innerHeight;

    const bottomMarginPx = 36;
    const desiredBottom = viewportBottom - bottomMarginPx;
    const diff = rect.bottom - desiredBottom;

    if (Math.abs(diff) > 2) {
      instantScrollBy(diff);
    }
  }

  document.addEventListener("focusin", (e) => {
    const target = e.target;
    if (!target) return;

    const row = target.closest(ROW_SELECTORS);
    if (row) pinRowToBottom(row);
  }, true);

  function clampTop(){
    const el = SCROLLER();
    if (el === document.documentElement || el === document.body || el === document.scrollingElement){
      if (window.scrollY < 0) window.scrollTo(0,0);
    } else {
      if (el.scrollTop < 0) el.scrollTop = 0;
    }
  }

  window.addEventListener("scroll", clampTop, { passive: true });
})();

