    var startMs=0;
    try{var pct=parseFloat(prog||0)||0, dur=parseFloat(S._extRuntimeSec||0)||0; if(pct>0&&dur>0) startMs=Math.max(0,Math.round(dur*1000*(pct/100)));}catch(_e){}
    if(startMs>0){
      intent+=';l.position='+startMs+';i.position='+startMs+';S.position='+startMs+';S.startPosition='+startMs+';i.startfrom='+startMs+';B.forceresume=true;S.forcename='+encodeURIComponent(safe);
    }
    var pkg=(S.cfg&&S.cfg.extPkg)?String(S.cfg.extPkg):'chooser';
    if(pkg&&pkg!=='chooser') intent+=';package='+pkg;
    return intent+';end';
