                var left=(k==='ArrowLeft'||code===21||code===37), right=(k==='ArrowRight'||code===22||code===39), up=(k==='ArrowUp'||code===19||code===38), down=(k==='ArrowDown'||code===20||code===40), enter=(k==='Enter'||code===23||code===66);
                if(enter){ev.preventDefault();ev.stopPropagation();card.click();return;}
                if(!(left||right||up||down)) return;
