      var meta=['<span class="search-hero-pill">'+escM(tOf(it))+'</span>']; var y=yOf(it), r=rtOf(it), g=gOf(it);
      if(y) meta.push('<span>'+escM(y)+'</span>'); if(it.vote_average) meta.push('<span>★ '+Number(it.vote_average).toFixed(1)+'</span>'); if(r) meta.push('<span>'+escM(r)+'</span>'); if(g) meta.push('<span>'+escM(g)+'</span>');
