        +   '<div class="ltv-info-card">Hide individual series categories from the browser sidebar.</div>'
        +   (vsCats.length ? '<div class="ltv-btn-row" style="margin-bottom:10px"><button class="ltv-btn secondary" id="vs-show-all">Show All</button><button class="ltv-btn secondary" id="vs-hide-all">Hide All</button><button class="ltv-btn" style="background:rgba(220,38,55,.18);border-color:rgba(220,38,55,.4);color:#fca5a5" id="vs-reset">Reset</button></div>' : '')
        +   '<div class="ltv-list" id="vs-cats-list">'+vsRows+'</div>'
        + '</div>'
        + '<div class="ltv-section">'
        +   '<h4>Hide Adult Genres</h4>'
        +   '<div class="ltv-row-item"><div class="label"><div class="nm">Hide adult-rated series</div><div class="sub">Filters series titles matching the adult heuristic.</div></div>' + switchHtml(!!LTV_CFG.get('hideAdult')) + '</div>'
        + '</div>';
      return { html: html, bind: function(root){
        Array.prototype.forEach.call(root.querySelectorAll('#vs-cats-list .ltv-row-item'), function(node){
          var id = node.dataset.vsid; var sw = node.querySelector('.ltv-switch'); if(!sw||!id) return;
          sw.addEventListener('click', function(){
            var _h = LTV_CFG.get('hiddenVodSeriesCats') || {};
            if(_h[id]) delete _h[id]; else _h[id] = true;
            LTV_CFG.set('hiddenVodSeriesCats', _h); sw.classList.toggle('on', !_h[id]);
          });
        });
        var _sa=root.querySelector('#vs-show-all'), _ha=root.querySelector('#vs-hide-all'), _rs=root.querySelector('#vs-reset');
        if(_sa) _sa.addEventListener('click', function(){ var _h={}; LTV_CFG.set('hiddenVodSeriesCats',_h); root.querySelectorAll('#vs-cats-list .ltv-switch').forEach(function(s){ s.classList.add('on'); }); });
        if(_ha) _ha.addEventListener('click', function(){ var _h={}; vsCats.forEach(function(c){ _h[String(c.id)]=true; }); LTV_CFG.set('hiddenVodSeriesCats',_h); root.querySelectorAll('#vs-cats-list .ltv-switch').forEach(function(s){ s.classList.remove('on'); }); });
        if(_rs) _rs.addEventListener('click', function(){ LTV_CFG.set('hiddenVodSeriesCats',{}); root.querySelectorAll('#vs-cats-list .ltv-switch').forEach(function(s){ s.classList.add('on'); }); });
        bindSwitch(root.querySelector('.ltv-switch'), function(){ return LTV_CFG.get('hideAdult'); }, function(v){ LTV_CFG.set('hideAdult', v); applySettings(); });
        try{ root.querySelector('#vs-launch').addEventListener('click', function(){
          try{ if(window.IptvVodBrowser&&IptvVodBrowser.open){ IptvVodBrowser.open('series'); } else if(window.Android&&typeof window.Android.openIptvVod==='function'){ window.Android.openIptvVod('series'); } }catch(_e){}
        }); }catch(_e2){}
      } };
