      +   '<button id="ltv-s-mic" tabindex="0" style="background:none;border:none;cursor:pointer;padding:8px;border-radius:50%;transition:all .2s;flex-shrink:0;display:flex;align-items:center;justify-content:center"><svg width="22" height="22" viewBox="0 0 22 22" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="8" y="1" width="6" height="11" rx="3" fill="rgba(220,38,55,0.9)"/><path d="M4 10a7 7 0 0014 0" stroke="rgba(220,38,55,0.9)" stroke-width="1.5" stroke-linecap="round" fill="none"/><line x1="11" y1="17" x2="11" y2="21" stroke="rgba(220,38,55,0.9)" stroke-width="1.5" stroke-linecap="round"/><line x1="8" y1="21" x2="14" y2="21" stroke="rgba(220,38,55,0.9)" stroke-width="1.5" stroke-linecap="round"/></svg></button>'
      + '</div>'
